// 조회
scwin.f_retrieve = async function () {
  let ret = await $c.gus.cfValidate($p, tb_searchCondition);
  if (!ret) {
    return;
  }
  if ($c.util.isEmpty($p, ed_stStockInoutDt.getValue()) || $c.util.isEmpty($p, ed_edStockInoutDt.getValue())) {
    $c.win.alert($p, "적용일자은(는) 필수 입력 항목입니다.");
    return;
  }
  let e = await $c.sbm.execute($p, sbm_condition);
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    scwin.sbm_condition_submitdone(e);
  }
};

// 그리드 데이터 엑셀로 다운
scwin.f_runExcel = async function () {
  var cntRow = ds_List1.getRowCount();
  if (cntRow > 0) {
    var cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      const options = {
        fileName: "양수양도내역.xlsx",
        sheetName: "양수양도내역",
        type: 4 + 8 + 16
      };
      const infoArr = [];
      $c.data.downloadGridViewExcel($p, gr_List1, options, infoArr);
    }
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.  
  }
};

